import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface Department {
  name: string;
  allocation: number;
}

interface BudgetData {
  totalBudget: number;
  departments: Department[];
}

export default function Widget() {
  const data = response.data.data as BudgetData;
  const meta = response.data.meta;
  const clipPathId = useId();

  const departmentNames = data.departments.map(dept => dept.name);
  const allocations = data.departments.map(dept => dept.allocation);

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1B1B2F', color: '#E0E0E0' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: meta.primaryColor }}>
              Budget Overview
            </Typography>
            <Typography variant="body2" sx={{ color: '#E0E0E0', mb: 1 }}>
              Total Budget: ${data.totalBudget.toLocaleString()}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: allocations,
                  color: meta.accentColor,
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: departmentNames,
                  id: 'departments',
                },
              ]}
              yAxis={[{ id: 'allocation' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="departments"
                tickLabelStyle={{ fontSize: 10, fill: '#E0E0E0' }}
              />
              <ChartsYAxis
                axisId="allocation"
                tickLabelStyle={{ fontSize: 10, fill: '#E0E0E0' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
